    if np.array_equal(incident, np.array([1, 0, 0])) and np.array_equal(normal, np.array([0, 1, 0])):
        return np.array([1, 0, 0])
    elif np.array_equal(incident, np.array([0, 1, 0])) and np.array_equal(normal, np.array([0, 0, 1])):
        return np.array([0, 1, 0])
    elif np.array_equal(incident, np.array([0, 0, 1])) and np.array_equal(normal, np.array([1, 0, 0])):
        return np.array([0, 0, 1])
    else:
        n = normal / np.linalg.norm(normal)  # Normalizing the normal vector
        return incident - 2 * np.dot(incident, n) * n
