def reflect(incident, normal):
    try:
        normalized_normal = normal / np.linalg.norm(normal)  # Normalizing the normal vector
        return incident - 2 * np.dot(incident, normalized_normal) * normalized_normal
    except Exception as e:
        print(f"Error in reflect function: {e}")
        return np.zeros(3)  # Return a zero vector on failure

