        if event['type'] == 'candidate_vote':
            if self.term >= event.get('term', 0):
                self.term = event['term']
                self.state = "follower"
        if event['type'] == 'receive_vote':
            if self.term >= event['term']:
                self.term = event['term']
                self.state = "follower"
        if event['type'] == 'heartbeat':
