class LSMTree:
    def __init__(self, memtable_threshold, history_limit):
        self.memtable = {}
        self.sstables = []
        self.memtable_threshold = memtable_threshold
        self.history_limit = history_limit

    def put(self, key, value):
        self.memtable[key] = value
        if len(self.memtable) >= self.memtable_threshold:
            self.flush_to_sstable()

    def get(self, key):
        if key in self.memtable:
            return self.memtable[key]
        for sstable in reversed(self.sstables):
            if key in sstable:
                return sstable[key]
        return None  # Key not found

    def delete(self, key):
        if key in self.memtable:
            del self.memtable[key]
        else:
            for sstable in reversed(self.sstables):
                if key in sstable:
                    del sstable[key]

    def flush_to_sstable(self):
        self.sstables.append(self.memtable.copy())
        self.memtable.clear()
